mapper.select:
select d.id as doc_id, d.kb_id, kb.name as kb_name, d.file_name as original_name, d.document_status as status, (select count(1) from km_document_chunk c where c.doc_id = d.id and c.is_active = 1) as chunk_count, concat('user-', coalesce(d.user_id, 0)) as uploader_name, d.created_at from km_document d left join km_knowledge_base kb on d.kb_id = kb.id where d.document_status = 'PENDING_REVIEW' and d.is_deleted = 0
and d.kb_id = #{kbId}
order by d.created_at desc limit #{offset}, #{pageSize}
